SET client_encoding TO 'UTF8';

SET check_function_bodies = false;

CREATE OR REPLACE VIEW view_wef_req_edu_chk (group_no, color, data_type, entry_id, entry_date, membership_no, remark, total_receive, edu_type, class_type, class_desc, child_id_card, date_of_birth, child_full_name) AS select
         group_no ,
         color ,
         data_type ,
         entry_id,   
         entry_date,   
         membership_no,  
         remark,   
         total_receive,   
         edu_type,   
         class_type,   
         class_desc,
         child_id_card,   
         date_of_birth,   
         child_full_name
FROM
( 
    select  
		2 as group_no ,
        'RED' as color,
           'EDU' as data_type,
            sc_wef_req.entry_id , 
            sc_wef_req.operate_date as entry_date , 
            sc_wef_req.membership_no , 
          
            CASE WHEN  sc_wef_req.approve_status  ='2' THEN  'รออนุมัติ'   ELSE sc_wef_req.remark END   as remark, 
            sc_wef_req.total_receive ,
            
            sc_wef_req_edu.edu_type ,  
            sc_wef_req_edu.class_type , 
            (  SELECT sc_wef_ucf_edu_class.class_desc  
           FROM sc_wef_ucf_edu_class  
           WHERE sc_wef_ucf_edu_class.class_type =  sc_wef_req_edu.class_type ) as class_desc ,
            sc_wef_req_edu.child_id_card , 
            sc_wef_req_edu.date_of_birth ,
            (   select sc_mem_m_ucf_prename.prename || sc_wef_req_edu.child_name || '  ' || sc_wef_req_edu.child_surname 
                from sc_mem_m_ucf_prename
                where sc_mem_m_ucf_prename.prename_code = sc_wef_req_edu.pre_name ) AS child_full_name
    from sc_wef_req
    ,sc_wef_req_edu
   ,sc_acc_m_account_constant
    where sc_wef_req.requestment_no = sc_wef_req_edu.requestment_no
    and sc_wef_req.cancel_status = '0'
    and (to_char(  sc_wef_req.operate_date ,'yyyy'))::numeric   > sc_acc_m_account_constant.present_account_year - 2 


union all
 

    select  
		3 as group_no ,
        'GREEN' as color,
           'APP' as data_type,
            sc_wef_req.entry_id , 
            sc_wef_req.operate_date as entry_date , 
            sc_wef_req.membership_no ,             
            sc_wef_req.remark , 
            sc_wef_req.total_receive ,

            sc_wef_req_edu.edu_type ,  
            sc_wef_req_edu.class_type , 
            (  SELECT sc_wef_ucf_edu_class.class_desc  
           FROM sc_wef_ucf_edu_class  
           WHERE sc_wef_ucf_edu_class.class_type =  sc_wef_req_edu.class_type ) as class_desc ,
            sc_wef_req_edu.child_id_card , 
            sc_wef_req_edu.date_of_birth ,
            (   select sc_mem_m_ucf_prename.prename || sc_wef_req_edu.child_name || '  ' || sc_wef_req_edu.child_surname 
                from sc_mem_m_ucf_prename
                where sc_mem_m_ucf_prename.prename_code = sc_wef_req_edu.pre_name ) AS child_full_name
    from sc_wef_req
    ,sc_wef_req_edu
   ,sc_acc_m_account_constant
    where sc_wef_req.requestment_no = sc_wef_req_edu.requestment_no
     and (to_char(  sc_wef_req.operate_date ,'yyyy'))::numeric   <= sc_acc_m_account_constant.present_account_year -2
     and sc_wef_req.approve_status = '1' 
       

union all


  SELECT 
	     1 as group_no ,
         'BLUE' as color,
         'CHK' as data_type,
         sc_wef_req_edu_chk.entry_id,   
         sc_wef_req_edu_chk.entry_date,   
         sc_wef_req_edu_chk.membership_no,  
         '' as remark,   
         0 as total_receive,   
         '' as edu_type,   
         '' as class_type,   
         '' as class_desc ,
         sc_wef_req_edu_chk.child_id_card,   
         null as date_of_birth,   
         '' as  child_full_name  
    FROM sc_wef_req_edu_chk  
    WHERE 1=1
    
) tb
--WHERE membership_no = '051874'
 
ORDER BY group_no ,
         entry_date desc ,
         child_id_card;

